async (params, browser) => {
  // Open topic page
  await browser.open(`https://www.producthunt.com/topics/${params.topic_slug}`)

  // Wait for topic page to load
  await browser.waitForSelector('h1, [class*=\'topic\'], [class*=\'collection\'], [class*=\'hero\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load products
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract collection details
  const collection_data = await browser.evaluate(`const nameEl = document.querySelector('h1, [class*="topic"] h1, [class*="collection"] h1'); const descEl = document.querySelector('[class*="description"], [class*="about"] p, h1 + p'); const followersEl = document.querySelector('[class*="follower"] span, [class*="subscriber"]'); const products = []; const productEls = document.querySelectorAll('[data-test="post-item"], [class*="post-item"], a[href*="/posts/"]'); const seen = new Set(); for (let i = 0; i < productEls.length && products.length < 15; i++) { const el = productEls[i]; const nameEl2 = el.querySelector('h3, strong, [class*="title"]'); const href = el.getAttribute('href') || (el.querySelector('a[href*="/posts/"]') ? el.querySelector('a[href*="/posts/"]').href : ''); if (seen.has(href) || !href) continue; seen.add(href); const taglineEl = el.querySelector('p, [class*="tagline"]'); const upvotesEl = el.querySelector('[class*="vote"] span'); const imgEl = el.querySelector('img'); products.push({ name: nameEl2 ? nameEl2.textContent.trim() : '', tagline: taglineEl ? taglineEl.textContent.trim() : '', upvotes: upvotesEl ? upvotesEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', url: href.startsWith('http') ? href : 'https://www.producthunt.com' + href }); } return { topic: params.topic_slug, name: nameEl ? nameEl.textContent.trim() : '' + params.topic_slug + '', description: descEl ? descEl.textContent.trim().substring(0, 500) : '', followers: followersEl ? followersEl.textContent.trim() : '', product_count: products.length, products: products, url: window.location.href }`)

  return collection_data
}
